def require_api_auth(f):
    """Decorator to enforce API authentication via HMAC-based token."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get("Authorization")
        if not auth_header or not auth_header.startswith("Bearer "):
            logger.warning("Missing or malformed Authorization header")
            return jsonify({"error": "Authentication required"}), 401

        token = auth_header[7:]  # Strip "Bearer "

        # Validate the token: expected format is "timestamp:hmac_signature"
        parts = token.split(":", 1)
        if len(parts) != 2:
            logger.warning("Invalid token format")
            return jsonify({"error": "Invalid authentication token"}), 401

        timestamp_str, provided_signature = parts

        try:
            timestamp = int(timestamp_str)
        except ValueError:
            logger.warning("Invalid timestamp in token")
            return jsonify({"error": "Invalid authentication token"}), 401

        # Reject tokens older than 5 minutes to prevent replay attacks
        current_time = int(time.time())
        if abs(current_time - timestamp) > 300:
            logger.warning("Expired authentication token")
            return jsonify({"error": "Expired authentication token"}), 401

        # Verify HMAC signature
        expected_signature = hmac.new(
            API_SECRET_KEY.encode("utf-8"),
            timestamp_str.encode("utf-8"),
            hashlib.sha256,
        ).hexdigest()

        if not hmac.compare_digest(provided_signature, expected_signature):
            logger.warning("Invalid authentication signature")
            return jsonify({"error": "Invalid authentication token"}), 401

        return f(*args, **kwargs)

    return decorated_function


def validate_topic_name(topic_name):
    """
    Validate and sanitize the topic name.
    Returns (is_valid, error_message) tuple.
    """
    if not topic_name:
        return False, "Topic name is required"

    if not isinstance(topic_name, str):
        return False, "Topic name must be a string"

    # Strip whitespace
    topic_name = topic_name.strip()

    # Validate against allowed pattern to prevent injection
    if not TOPIC_NAME_PATTERN.match(topic_name):
        return False, (
            "Topic name contains invalid characters. "
            "Only alphanumeric characters, hyphens, underscores, and dots are allowed. "
            "Maximum length is 249 characters."
        )

    # Check against explicit allowlist - this is the critical security control
    if topic_name not in ALLOWED_TOPICS:
        logger.warning(
            "Attempt to publish to non-allowlisted topic: %s",
            topic_name,
        )
        return False, f"Topic '{topic_name}' is not in the allowed topics list"

    return True, None


def validate_message(message_data):
    """Validate the message payload."""
    if message_data is None:
        return False, "Message body is required"

    # Check message size
    serialized = json.dumps(message_data).encode("utf-8")
    if len(serialized) > MAX_MESSAGE_SIZE:
        return False, f"Message exceeds maximum size of {MAX_MESSAGE_SIZE} bytes"

    return True, None


@app.route("/api/v1/publish", methods=["POST"])
@require_api_auth
def publish_message():
    """
    Publish a message to a Kafka topic.

    Expected JSON body:
    {
        "topic": "allowed-topic-name",
        "key": "optional-message-key",
        "message": { ... message payload ... }
    }
    """
    # Parse request body
    if not request.is_json:
        return jsonify({"error": "Content-Type must be application/json"}), 400

    try:
        body = request.get_json(force=False, silent=False)
    except Exception:
        return jsonify({"error": "Invalid JSON body"}), 400

    if not isinstance(body, dict):
        return jsonify({"error": "Request body must be a JSON object"}), 400

    # Extract and validate topic name from request
    topic_name = body.get("topic")
    is_valid, error_msg = validate_topic_name(topic_name)
    if not is_valid:
        return jsonify({"error": error_msg}), 400

    topic_name = topic_name.strip()

    # Extract and validate message
    message_data = body.get("message")
    is_valid, error_msg = validate_message(message_data)
    if not is_valid:
        return jsonify({"error": error_msg}), 400

    # Extract optional message key
    message_key = body.get("key")
    if message_key is not None:
        if not isinstance(message_key, str) or len(message_key) > 256:
            return jsonify(
                {"error": "Message key must be a string with max 256 characters"}
            ), 400
        # Sanitize key
        message_key = message_key.strip()
        if not re.match(r"^[a-zA-Z0-9._\-:]+$", message_key):
            return jsonify(
                {"error": "Message key contains invalid characters"}
            ), 400

    # Publish to Kafka
    try:
        future = producer.send(
            topic_name,
            key=message_key,
            value=message_data,
        )
        # Block until the message is sent (with timeout)
        record_metadata = future.get(timeout=10)

        logger.info(
            "Message published to topic=%s partition=%d offset=%d",
            record_metadata.topic,
            record_metadata.partition,
            record_metadata.offset,
        )

        return jsonify({
            "status": "success",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
        }), 200

    except KafkaError as e:
        logger.error("Failed to publish message to topic %s: %s", topic_name, str(e))
        return jsonify({"error": "Failed to publish message"}), 500
    except Exception as e:
        logger.error("Unexpected error publishing to topic %s: %s", topic_name, str(e))
        return jsonify({"error": "Internal server error"}), 500


